Here's a sample code in Swift to calculate statistical metrics such as mean, standard deviation, and correlation coefficient. This can be used as part of a coding test to evaluate a candidate's proficiency in data analysis:
```swift
import Foundation

func mean(numbers: [Double]) -> Double {
    return numbers.reduce(0, +) / numbers.count
}

func standardDeviation(numbers: [Double]) -> Double {
    let mean = mean(numbers: numbers)
    let squaredDiffs = numbers.map { x -> Double in
        return (x - mean) * (x - mean)
    }
    let avgSquaredDiff = mean(numbers: squaredDiffs)
    let squareRootOfAvgSquaredDiff = sqrt(avgSquaredDiff)
    return squareRootOfAvgSquaredDiff
}

func sampleCorrelationCoefficient(x: [Double], y: [Double]) -> Double {
    let xMean = mean(numbers: x)
    let yMean = mean(numbers: y)
    let xVariance = standardDeviation(numbers: x) * (x.count - 1)
    let yVariance = standardDeviation(numbers: y) * (y.count - 1)
    let covariance = x.zip(y).map { (a, b) -> Double in
        return (a - xMean) * (b - yMean)
    }.reduce(0, +)
    let correlationCoefficient = covariance / (sqrt(xVariance) * sqrt(yVariance))
    return correlationCoefficient
}

let x = [1, 2, 3, 4, 5]
let y = [4, 5, 6, 8, 9]

let meanX = mean(numbers: x)
print("Mean of x: \(meanX)")

let meanY = mean(numbers: y)
print("Mean of y: \(meanY)")

let standardDeviationX = standardDeviation(numbers: x)
print("Standard deviation of x: \(standardDeviationX)")

let standardDeviationY = standardDeviation(numbers: y)
print("Standard deviation of y: \(standardDeviationY)")

let correlationCoefficient = sampleCorrelationCoefficient(x: x, y: y)
print("Correlation coefficient between x and y: \(correlationCoefficient)")
```
