func main() {
	oliveOil := Ingredient{Name: "olive oil", Amount: 1, Unit: "tablespoon", Quality: "extra virgin", Origin: "Italy"}
	butter := Ingredient{Name: "butter", Amount: 2, Unit: "tablespoon", Quality: "unsalted", Origin: "France"}
