	fmt.Println("Suggested cooking duration: ", duration)
}

type Ingredient struct {
	Name    string
	Amount  int
	Unit    string
	Quality string
	Origin  string
}

func suggestion(oliveOil, butter, onions Ingredient) (int, string) {
	temp := 350 // Default temperature
	duration := "10-12 minutes"    // Default cooking time

	consider := func(i Ingredient) {
		if i.Origin == "Italy" || i.Origin == "France" {
			temp += 10
		}
		if i.Quality == "extra virgin" || i.Quality == "unsalted" {
			duration = "5 minutes less"
		}
	}

	consider(oliveOil)
	consider(butter)
	consider(onions)

	return temp, duration
}
```

